import React, { useCallback, useEffect, useMemo, useState } from 'react';
import {
  Select,
  Pagination,
  StatusBadge,
  DateRangeFilter,
  SearchTextInput,
  dispatchAppToast,
  LinPageLayout,
  useCatalogTableBusy,
} from '@linm-soft/common-components';
import type { DateRangeValue } from '@linm-soft/common-components';
import { useAppDispatch } from '../../../store/hooks';
import { useHddtListFilterState } from '../../../hooks/useHddtListFilterState';
import { useHddtPermissions } from '../../../hooks/useHddtPermissions';
import { purchasingService } from '../../../services/mh/purchasingService';
import type { EinvoiceDto } from '../../../services/mh/models';
import { VOUCHER_STATUS_OPTIONS, PAGE_SIZE } from '../../../utils/constants';
import { LIST_FILTER_SCOPE } from '../../../constants/listFilterScopes';
import { hddtPageLabels } from '../../../constants/hddtPageLabels';
import { formatDate, formatMoneyVnd } from '../../../utils/formatters';
import { getApiErrorMessage } from '../../../utils/getApiErrorMessage';
import erp from '../../../styles/erpPage.module.css';

const TEST_ID = 'erp-mh-hddt';
const PAGE_ID = 'mh-hddt';

function normalizeSearch(s: string): string {
  return s.trim().toLowerCase();
}

function matchesSearch(row: EinvoiceDto, q: string): boolean {
  if (!q) return true;
  const hay = `${row.code} ${row.invoiceNo} ${row.supplierName ?? ''}`.toLowerCase();
  return hay.includes(q);
}

function canVerifyRow(row: EinvoiceDto): boolean {
  return row.status !== 'Verified' && row.status !== 'Posted';
}

const HddtPage: React.FC = () => {
  const dispatch = useAppDispatch();
  const { canVerify } = useHddtPermissions();
  const {
    initialized,
    fromDate,
    toDate,
    datePreset,
    applyDateRange,
    searchDraft,
    setSearchDraft,
    search,
    setSearch,
    status,
    setStatus,
    page,
    setPage,
    resetPage,
  } = useHddtListFilterState(LIST_FILTER_SCOPE.hddt);

  const [items, setItems] = useState<EinvoiceDto[]>([]);
  const [totalCount, setTotalCount] = useState(0);
  const [loading, setLoading] = useState(false);
  const [reloadKey, setReloadKey] = useState(0);
  const [activeId, setActiveId] = useState<string | null>(null);

  const refresh = useCallback(() => setReloadKey(k => k + 1), []);
  const handleSearch = useCallback(() => {
    setSearch(searchDraft.trim());
    resetPage();
  }, [searchDraft, setSearch, resetPage]);
  const { showTableLoading } = useCatalogTableBusy(loading);

  const activeRow = useMemo(
    () => items.find(r => r.id === activeId) ?? null,
    [items, activeId],
  );

  useEffect(() => {
    if (!initialized) return;
    let cancelled = false;
    setLoading(true);
    const t = setTimeout(() => {
      purchasingService.getEinvoices({
        status: status || undefined,
        fromDate: fromDate ? `${fromDate}T00:00:00.000Z` : undefined,
        toDate: toDate ? `${toDate}T23:59:59.999Z` : undefined,
        page,
        pageSize: PAGE_SIZE,
      })
        .then(res => {
          if (cancelled) return;
          const q = normalizeSearch(search);
          const filtered = q ? res.items.filter(r => matchesSearch(r, q)) : res.items;
          setItems(filtered);
          setTotalCount(q ? filtered.length : res.totalCount);
        })
        .catch(err => {
          if (!cancelled) {
            dispatchAppToast(dispatch, {
              message: getApiErrorMessage(err, hddtPageLabels.loadError),
              type: 'error',
            });
          }
        })
        .finally(() => { if (!cancelled) setLoading(false); });
    }, 0);
    return () => { cancelled = true; clearTimeout(t); };
  }, [initialized, status, fromDate, toDate, page, search, dispatch, reloadKey]);

  const handleVerify = useCallback(async (id: string) => {
    try {
      await purchasingService.verifyEinvoice(id);
      dispatchAppToast(dispatch, { message: hddtPageLabels.verifySuccess, type: 'success' });
      refresh();
    } catch (err: unknown) {
      dispatchAppToast(dispatch, {
        message: getApiErrorMessage(err, hddtPageLabels.verifyError),
        type: 'error',
      });
    }
  }, [dispatch, refresh]);

  const canVerifyActive = Boolean(activeRow && canVerifyRow(activeRow) && canVerify);

  const voucherToolbar = useMemo(
    () => ({
      testIdPrefix: TEST_ID,
      onRefresh: refresh,
      canCreate: false,
      canView: false,
      canEdit: false,
      canApprove: canVerifyActive,
      onApprove: () => activeRow && handleVerify(activeRow.id),
      approveLabel: 'Xác thực',
    }),
    [refresh, canVerifyActive, activeRow, handleVerify],
  );

  const filterItems = useMemo(
    () => [
      {
        testId: `${TEST_ID}-field-dateRange`,
        content: (
          <DateRangeFilter
            label="Thời gian"
            fullWidth
            testId={`${TEST_ID}-date-range`}
            fromDate={fromDate}
            toDate={toDate}
            preset={datePreset}
            onChange={(v: DateRangeValue) => {
              applyDateRange(v.fromDate, v.toDate, v.preset);
              resetPage();
            }}
          />
        ),
      },
      {
        testId: `${TEST_ID}-field-search`,
        content: (
          <SearchTextInput
            label="Tìm kiếm"
            value={searchDraft}
            onChange={setSearchDraft}
            onSearch={handleSearch}
            placeholder="Số HĐ, mã, NCC…"
            testId={`${TEST_ID}-search-text`}
          />
        ),
      },
      {
        testId: `${TEST_ID}-field-status`,
        content: (
          <Select
            label="Trạng thái"
            value={status}
            onChange={e => { setStatus(e.target.value); resetPage(); }}
            options={VOUCHER_STATUS_OPTIONS}
            fullWidth
            data-testid={`${TEST_ID}-filter-status`}
          />
        ),
      },
    ],
    [
      fromDate,
      toDate,
      datePreset,
      searchDraft,
      status,
      applyDateRange,
      resetPage,
      setSearchDraft,
      handleSearch,
      setStatus,
    ],
  );

  const listBody = !showTableLoading && items.length === 0 ? (
    <div className={erp.empty} data-testid={`${TEST_ID}-empty`}>
      <i className="fas fa-inbox" />
      <p>{hddtPageLabels.empty}</p>
    </div>
  ) : !showTableLoading ? (
    <div className={erp.tableWrapper} data-testid={`${TEST_ID}-grid`}>
      <table className={erp.table}>
        <thead>
          <tr>
            <th>Số HĐ</th>
            <th>Ngày</th>
            <th>NCC</th>
            <th className={erp.colRight}>Tổng tiền</th>
            <th>Nguồn</th>
            <th>Trạng thái</th>
          </tr>
        </thead>
        <tbody>
          {items.map(e => (
            <tr
              key={e.id}
              className={e.id === activeId ? erp.rowSelected : undefined}
              onClick={() => setActiveId(e.id)}
              data-testid={`${TEST_ID}-row-${e.id}`}
            >
              <td><code>{e.invoiceNo || e.code}</code></td>
              <td>{formatDate(e.invoiceDate)}</td>
              <td>{e.supplierName ?? '—'}</td>
              <td className={erp.colRight}>{formatMoneyVnd(e.totalAmount)}</td>
              <td>{e.source ?? '—'}</td>
              <td><StatusBadge status={e.status} /></td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  ) : null;

  return (
    <div
      className={erp.voucherListRoot}
      data-voucher-list-page
      data-testid={`${TEST_ID}-list`}
    >
      <LinPageLayout
        kind="voucher"
        testIdPrefix={TEST_ID}
        pageId={PAGE_ID}
        pageClassName={`${erp.catalogListPage} ${erp.voucherListPage}`}
        header={{
          title: hddtPageLabels.listTitle,
          titleIconClass: 'fas fa-file-invoice',
          pageId: PAGE_ID,
        }}
        voucherToolbar={voucherToolbar}
        listTitle={hddtPageLabels.listSubtitle}
        listRowMenuHelp
        filterItems={filterItems}
        filterMaxWidthPx={1000}
        showTableLoading={showTableLoading}
        skeletonRows={6}
        footer={(
          <div className={erp.paginationRow} data-testid={`${TEST_ID}-pagination`}>
            <span className={erp.totalCount}>Tổng: {totalCount} hóa đơn</span>
            <Pagination
              currentPage={page}
              totalPages={Math.max(1, Math.ceil(totalCount / PAGE_SIZE))}
              totalCount={totalCount}
              pageSize={PAGE_SIZE}
              onPageChange={p => { setPage(p); setActiveId(null); }}
            />
          </div>
        )}
      >
        {listBody}
      </LinPageLayout>
    </div>
  );
};

export default HddtPage;
